<?php
namespace Database\Seeders;use Illuminate\Database\Seeder;use App\Models\{User,Category,CulinaryPlace,Menu,Gallery,Review,Reservation};use Illuminate\Support\Str;
class PalembangCulinarySeeder extends Seeder{public function run():void{$cats=['Pempek','Tekwan','Model','Pindang','Mie Celor','Kue Tradisional','Kopi','Seafood'];foreach($cats as $c)Category::firstOrCreate(['slug'=>Str::slug($c)],['name'=>$c,'description'=>'Kategori kuliner khas '.$c,'status'=>'active']);$owners=collect(range(1,20))->map(fn($i)=>User::firstOrCreate(['email'=>"owner$i@smwkp.test"],['name'=>"Pemilik Usaha $i",'phone'=>'0813'.str_pad($i,8,'0',STR_PAD_LEFT),'password'=>bcrypt('password'),'status'=>'active']));$owners->each->assignRole('pemilik_usaha');$tourists=collect(range(1,100))->map(fn($i)=>User::firstOrCreate(['email'=>"wisatawan$i@smwkp.test"],['name'=>"Wisatawan $i",'phone'=>'0821'.str_pad($i,8,'0',STR_PAD_LEFT),'password'=>bcrypt('password'),'status'=>'active']));$tourists->each->assignRole('wisatawan');$names=['Pempek Candy','Pempek Vico','Pempek Nony','Pempek Beringin','Pempek Lince','Tekwan Dempo','Model Gandum','Pindang Musi Rawas','Mie Celor 26 Ilir','Martabak HAR','Kemplang Panggang Ilir','Kopi Besemah','Pindang Pegagan','Brengkes Tempoyak','Lenggang Panggang'];for($i=1;$i<=50;$i++){ $name=$names[($i-1)%count($names)]." Cabang $i";$place=CulinaryPlace::firstOrCreate(['slug'=>Str::slug($name)],['owner_id'=>$owners[$i%20]->id,'category_id'=>Category::inRandomOrder()->first()->id,'name'=>$name,'description'=>'Destinasi kuliner Palembang dengan rasa autentik dan pelayanan ramah.','address'=>'Jl. Kuliner Palembang No. '.$i,'district'=>['Ilir Barat I','Ilir Timur II','Seberang Ulu I','Sukarami','Kemuning'][$i%5],'city'=>'Palembang','province'=>'Sumatera Selatan','postal_code'=>'30'.str_pad($i,3,'0',STR_PAD_LEFT),'latitude'=>-2.99+($i/10000),'longitude'=>104.75+($i/10000),'phone'=>'0711'.str_pad($i,5,'0',STR_PAD_LEFT),'average_price'=>15000+($i*1000),'open_time'=>'08:00','close_time'=>'21:00','halal_status'=>'verified','verification_status'=>'approved','featured'=>$i<=8]);Menu::create(['culinary_place_id'=>$place->id,'name'=>'Paket Khas Palembang','description'=>'Menu andalan khas Palembang','price'=>25000,'status'=>'available']);Gallery::create(['culinary_place_id'=>$place->id,'image_path'=>'galleries/place-'.$i.'.jpg','caption'=>$name,'sort_order'=>1]);} $places=CulinaryPlace::all();for($i=1;$i<=200;$i++){Review::firstOrCreate(['user_id'=>$tourists[$i%100]->id,'culinary_place_id'=>$places[$i%50]->id],['rating'=>($i%5)+1,'review_text'=>'Rasa enak, lokasi mudah dijangkau, cocok untuk wisata kuliner.','status'=>'published']);}for($i=1;$i<=100;$i++){Reservation::create(['user_id'=>$tourists[$i%100]->id,'culinary_place_id'=>$places[$i%50]->id,'reservation_date'=>now()->addDays($i%30)->toDateString(),'reservation_time'=>'18:00','guest_count'=>($i%6)+1,'note'=>'Reservasi wisata kuliner','status'=>['pending','confirmed','completed'][$i%3]]);}}}
